	subtitle.property("ADBE Text Properties").property(4).property(1).property(1).property(1).property("ADBE Text Percent Start").expression = "m = thisLayer;\r\nn=0;\r\nlen = thisComp.duration;\r\n\r\n// Reference the Checkbox Control\r\nvar checkbox = thisLayer.effect(\"Enable Type On\")(\"Checkbox\").value;\r\n\r\n// Only run the typing effect if the checkbox is checked\r\nif (checkbox == 1) {\r\n\r\n    if (m.marker.numKeys > 0){\r\n        n = m.marker.nearestKey(time).index;\r\n            if (m.marker.key(n).time > time) n--;\r\n    if(n > 0){\r\n        mt = m.marker.key(n).time;\r\n    if(time < mt+len){\r\n        driverMin = m.marker.key(n).time;\r\n        driverMax = m.marker.key(n).time+(marker.key(n).duration/5);\r\n        outputMin = 0;\r\n        outputMax = 100;\r\n        linear(time, driverMin, driverMax, outputMin, outputMax);\r\n        \r\n            }else value;\r\n        }else value;\r\n    }else value;\r\n}else value; // If the checkbox isn't checked, return the original value";
	//"m = thisLayer;\rn=0;\rlen = thisComp.duration;\r    if (m.marker.numKeys > 0){\r        n = m.marker.nearestKey(time).index;\r            if (m.marker.key(n).time > time) n--;\r    if(n > 0){\r        mt = m.marker.key(n).time;\r    if(time < mt+len){\r        driverMin = m.marker.key(n).time;\r        driverMax = m.marker.key(n).time+(marker.key(n).duration/5);\r        outputMin = 0;\r        outputMax = 100;\r        linear(time, driverMin, driverMax, outputMin, outputMax);\r        \r            }else value;\r        }else value;\r    }else value;";
	subtitle.property("ADBE Transform Group").property("ADBE Opacity").expression = "effect(\"Subtitle Setup\")(\"Font Opacity\")";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(1).property("ADBE Vector Rect Size").expression = "var t = thisComp.layer(\"SUBTITLE\").sourceRectAtTime();\rx = t.width+thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Offset X\");\ry = t.height+thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Offset Y\");\r[x,y]";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(1).property("ADBE Vector Rect Roundness").expression = "thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Box Roundness\")";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(2).property("ADBE Vector Stroke Color").expression = "thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Stroke Color\")";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(2).property("ADBE Vector Stroke Width").expression = "if (thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Stroke\")==0) {0} else {thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Stroke Width\")}";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(3).property("ADBE Vector Fill Color").expression = "thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Box Color\")";
	txtbox.property("ADBE Root Vectors Group").property(1).property(2).property(3).property("ADBE Vector Fill Opacity").expression = "thisComp.layer(\"SUBTITLE\").effect(\"Subtitle Setup\")(\"Opacity\")";
	txtbox.property("ADBE Root Vectors Group").property(1).property(3).property("ADBE Vector Anchor").expression = "x = 0;\ry = content(\"Rectangle 1\").content(\"Rectangle Path 1\").size[1]/2;\r\r[x,y-y]";
	txtbox.property("ADBE Transform Group").property("ADBE Position").expression = "t = parent.sourceRectAtTime();\ry = content(\"Rectangle 1\").content(\"Rectangle Path 1\").size[1]/2;\rx =0;\r[x+t.width/2,t.top+t.height/2]";
	txtbox.property("ADBE Transform Group").property("ADBE Opacity").expression = "m = thisComp.layer(\"SUBTITLE\");\rn=0;\rif (m.marker.numKeys > 0){\r  n = m.marker.nearestKey(time).index;\r  if (m.marker.key(n).time > time) n--;\r}\rif (n > 0 && m.marker.key(n).duration+m.marker.key(n).time>time) {\r    100\r} else  {0}";
